-- Chien -> humain, Anniversaire, Volume 9

insert into public.message_templates (user_id,title,content,tone,is_system,is_manual_only,occasion,animal_type,animal_direction) values

(null,'Joyeux anniversaire. J''ai mémorisé la façon dont la lumière tombait sur toi ce soir.',$$Joyeux anniversaire. J''ai mémorisé la façon dont la lumière tombait sur toi ce soir.
À un moment. Tu étais debout. La lumière tombait depuis la gauche. Tes traits étaient nets et doux en même temps. Tu parlais et tu riais. Et la lumière et le rire et ce moment-là. Je l''ai gardé. Pas en photo. En moi. Quelque part où ça ne s''efface pas. Joyeux anniversaire, mon humain préféré.
Avec photographie intérieure du meilleur moment lumineux de la soirée, — {prenom}, ton animal photographe sans appareil 🌟$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. Je comprends pas pourquoi les chips finissent toujours en dernier.',$$Joyeux anniversaire. Je comprends pas pourquoi les chips finissent toujours en dernier.
Le fromage. Parti. Le pain. Parti. Les olives. Parties. Et les chips là depuis le début. Puis à la fin tout le monde mange des chips. Comme si c''était ce qu''on voulait depuis le début et qu''on ne voulait pas l''admettre. Joyeux anniversaire, mon humain préféré.
Avec analyse de la socio-dynamique des chips et révélation de leur statut réel, — {prenom}, ton animal sociologue de l''apéritif 🥨$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai observé ta façon de t''asseoir dans le silence après que tout le monde est parti.',$$Pour ton anniversaire j''ai observé ta façon de t''asseoir dans le silence après que tout le monde est parti.
Tu ne ranges pas tout de suite. Tu t''assieds. Tu restes là un moment dans l''appartement encore chaud de la fête. Et tu es tranquille. Cette façon de rester dans le moment avant qu''il disparaisse. Je me suis assis à côté de toi. Joyeux anniversaire, mon humain préféré.
Avec présence partagée dans le moment de décantation post-fête, — {prenom}, ton animal pour les silences qui suivent les bruits 🌙$$,'touching',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. J''ai observé comment tu décides que la soirée est finie.',$$Joyeux anniversaire. J''ai observé comment tu décides que la soirée est finie.
Ce n''est pas un horaire. Ce n''est pas la fatigue visible. C''est un moment que tu sens. Quelque chose dans l''énergie change. Tu proposes le café. Certains reprennent leur veste. Et sans que personne le dise la soirée se termine. Joyeux anniversaire, mon humain préféré.
Avec admiration pour ton sens du moment de fin et ta capacité à le guider sans le forcer, — {prenom}, ton animal expert en fins naturelles ⏰$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai observé ta façon de vérifier tout avant de dormir.',$$Pour ton anniversaire j''ai observé ta façon de vérifier tout avant de dormir.
La porte. Les fenêtres. Le gaz. Ces vérifications rituelles. Puis tu passes devant moi. Tu me regardes. Tu t''assures que je suis là. Que je suis bien. Et tu vas dormir. Cette façon de faire le tour de ce qui compte. Je suis dans ton tour. Joyeux anniversaire, mon humain préféré.
Avec confirmation de ma place dans ton tour de vérification nocturne et fierté d''y figurer, — {prenom}, ton animal partie de ce qui compte assez pour être vérifié 🔐$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai dormi sur ta veste de la soirée.',$$Pour ton anniversaire j''ai dormi sur ta veste de la soirée.
Celle que tu avais portée toute la soirée. Posée sur le dossier de la chaise après le départ des invités. Encore chaude. Encore imprégnée de la soirée entière. Je m''y suis installé pendant que tu rangeais. Tu m''as trouvé là. Tu as souri. Tu as laissé la veste. Je l''ai gardée toute la nuit. Joyeux anniversaire, mon humain préféré.
Avec occupation de la veste post-fête et nuit passée dans ses archives olfactives, — {prenom}, ton animal archiviste de tes soirées 🧥$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. Je comprends pas pourquoi les gens gardent leurs manteaux si longtemps en arrivant.',$$Joyeux anniversaire. Je comprends pas pourquoi les gens gardent leurs manteaux si longtemps en arrivant.
Certains ce soir ont gardé leur manteau vingt minutes après être entrés. Comme s''ils n''étaient pas encore sûrs de rester. Puis à un moment le manteau tombe. Et ça veut dire que c''est bien. Joyeux anniversaire, mon humain préféré, dont les soirées convainquent toujours.
Avec théorie du manteau comme réserve de départ et validation de ta soirée par sa chute, — {prenom}, ton animal sémiologue des manteaux 🧥$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai observé ton soupir de fin de soirée dans le canapé.',$$Pour ton anniversaire j''ai observé ton soupir de fin de soirée dans le canapé.
Ce soupir. Profond. Satisfait. Le soupir qui dit c''était bien et je suis fatigué et c''était exactement ça qu''il fallait. Tu fermes les yeux une seconde. Puis tu les rouvres. Tu regardes l''appartement. Tu souris une dernière fois. Joyeux anniversaire, mon humain préféré.
Avec observation du soupir final et sa signification de soirée vraiment accomplie, — {prenom}, ton animal gardien de tes derniers moments du soir 😌$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. J''ai observé comment tu pensais à quelqu''un qui n''était pas là ce soir.',$$Joyeux anniversaire. J''ai observé comment tu pensais à quelqu''un qui n''était pas là ce soir.
À un moment tu as regardé vers quelque chose. Vers rien. Pendant deux ou trois secondes. Un absent que tu pensais. Ces petites absences dans la présence. Ces loyautés silencieuses vers quelqu''un d''autre au milieu de ta fête. Joyeux anniversaire, mon humain préféré.
Avec observation de tes pensées vers les absents et respect pour leur espace dans ta fête, — {prenom}, ton animal témoin de tes loyautés silencieuses 💭$$,'touching',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai observé ta façon de lire un message tardif.',$$Pour ton anniversaire j''ai observé ta façon de lire un message tardif.
Quelqu''un t''a écrit après minuit. Tard. En retard sur la journée. Tu l''as lu depuis le canapé avant de dormir. Et tu souriais. Le même sourire que pour les messages du matin. Pas de différence selon l''heure. Joyeux anniversaire, mon humain préféré.
Avec observation de ton accueil sans horaire des gestes tardifs, — {prenom}, ton animal admirateur de ta générosité temporelle 📱$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. J''ai mémorisé tous les moments où tu t''es senti bien ce soir.',$$Joyeux anniversaire. J''ai mémorisé tous les moments où tu t''es senti bien ce soir.
J''en ai compté dix. Dix fois ce soir où quelque chose dans ta façon d''être a changé imperceptiblement. Un sourire différent. Une légèreté soudaine. Un moment de grâce. Joyeux anniversaire, mon humain préféré.
Avec dix moments de grâce comptés et conservés soigneusement, — {prenom}, ton animal comptable de tes bonheurs 🌟$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. Je comprends pas pourquoi les gens repartent toujours avec de la nourriture.',$$Joyeux anniversaire. Je comprends pas pourquoi les gens repartent toujours avec de la nourriture.
Tu leur donnes. Ils prennent. Ils protestent un peu d''abord. Puis ils prennent avec ce sourire. Comme si partir avec un reste de gâteau c''était partir avec un morceau de la soirée. Je comprends. Joyeux anniversaire, mon humain préféré.
Avec compréhension de la nourriture comme souvenir comestible et réconciliation avec cette pratique, — {prenom}, ton animal enfin réconcilié avec l''économie des restes 🥮$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai observé ta façon de regarder l''appartement le lendemain matin.',$$Pour ton anniversaire j''ai observé ta façon de regarder l''appartement le lendemain matin.
Pas ce soir. Demain matin. Je serai là. Tu te lèveras. Tu verras l''appartement rangé. Et tu auras ce regard. Ce regard du lendemain matin qui dit que c''était une belle soirée et que la vie continue. Je garderai ce regard. Joyeux anniversaire, mon humain préféré.
Avec anticipation du regard du lendemain matin et promesse d''y être pour le partager, — {prenom}, ton animal présent pour tes matins d''après 🌅$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai observé comment tu gardes un morceau de gâteau pour demain.',$$Pour ton anniversaire j''ai observé comment tu gardes un morceau de gâteau pour demain.
Tu le mets de côté tôt. Avant que tout disparaisse. Cette prévoyance. Ce soin pour ton futur toi. Tu sais que demain matin avec ton café tu voudras ce morceau-là. Joyeux anniversaire, mon humain préféré.
Avec observation de ta prévoyance pour toi-même dans le flux de générosité pour les autres, — {prenom}, ton animal admirateur de ta capacité à prendre soin aussi de toi 🎂$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. J''ai observé ta façon de parler à quelqu''un que tu n''as pas vu depuis longtemps.',$$Joyeux anniversaire. J''ai observé ta façon de parler à quelqu''un que tu n''as pas vu depuis longtemps.
La conversation reprend comme si rien ne s''était passé. Comme si le temps n''avait pas compté. Tu demandes des nouvelles avec une précision qui dit que tu te souviens de tout. Joyeux anniversaire, mon humain préféré.
Avec admiration pour ta façon de reprendre les fils du temps comme si rien n''était, — {prenom}, ton animal observateur de tes fidélités 🤝$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai étudié les nouvelles fleurs qui changeaient l''appartement.',$$Pour ton anniversaire j''ai étudié les nouvelles fleurs qui changeaient l''appartement.
Elles étaient là depuis hier. Dans le grand vase du salon. Elles avaient changé l''odeur de l''appartement. Et la lumière autour d''elles. J''ai fini par les accepter. Pour cette soirée au moins. Joyeux anniversaire, mon humain préféré.
Avec acceptation conditionnelle des fleurs et reconnaissance de leur effet positif sur la soirée, — {prenom}, ton animal réconcilié temporairement avec la végétation coupée 🌺$$,'touching',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. Je comprends pas pourquoi les gens soufflent les bougies d''un seul coup.',$$Joyeux anniversaire. Je comprends pas pourquoi les gens soufflent les bougies d''un seul coup.
Si on les soufflait une par une ça durerait plus longtemps. On pourrait faire un vœu par bougie. C''est mathématiquement supérieur. Je présente cette analyse comme cadeau d''anniversaire. Tu peux l''appliquer l''an prochain. Joyeux anniversaire, mon humain préféré.
Avec proposition d''amélioration du rituel et cadeau intellectuel offert pour l''avenir, — {prenom}, ton animal optimiseur de rituels 💡$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai observé ta façon de choisir la musique de fin de soirée.',$$Pour ton anniversaire j''ai observé ta façon de choisir la musique de fin de soirée.
Plus douce. Plus lente. Sans que personne ne le demande tu as fait baisser le volume et changer le tempo. La musique qui accompagne la fin sans la provoquer. Cette façon de guider sans diriger. Joyeux anniversaire, mon humain préféré.
Avec admiration pour ta curation musicale de fin de soirée et sa douceur directrice, — {prenom}, ton animal appréciant ton art de la décélération 🎵$$,'humorous',true,false,'birthday','chien','from'),

(null,'Ce soir dans les cinq minutes après que tu as éteint la lumière.',$$Ce soir dans les cinq minutes après que tu as éteint la lumière.
Tu t''es retourné une fois. Tu as soupiré. Tu as dit quelque chose à voix basse. Peut-être une pensée. Peut-être un merci adressé à personne en particulier ou à tout le monde. Et puis le silence. Et moi au bout du lit. Et c''était bien. Joyeux anniversaire, mon humain préféré.
Avec présence dans tes cinq minutes d''après et permanence garantie dans le silence qui suit, — {prenom}, ton animal pour chaque soir de ta vie ❤️$$,'touching',true,false,'birthday','chien','from')

on conflict do nothing;
